input.command:
kubectl -n ingress-nginx patch deployment ingress-nginx-controller --type=json -p='[
  {"op":"add","path":"/spec/template/spec/containers/0/args/-","value":"--tcp-services-configmap=$(POD_NAMESPACE)/tcp-services"},
  {"op":"add","path":"/spec/template/spec/containers/0/ports/-","value":{"name":"sql-26257","containerPort":26257,"protocol":"TCP"}}
]' && echo "deploy patched"

kubectl -n ingress-nginx patch svc ingress-nginx-controller --type=json -p='[
  {"op":"add","path":"/spec/ports/-","value":{"name":"sql-26257","port":26257,"targetPort":"sql-26257","protocol":"TCP"}}
]' && echo "svc patched"
